import React from 'react';
import { Link } from 'react-router-dom';
import './Categories.css';

const CATEGORIES = [
  {
    name: 'Necklaces',
    count: '48 items',
    icon: '📿',
    img: 'https://picsum.photos/seed/cat-necklace/600/800',
  },
  {
    name: 'Rings',
    count: '64 items',
    icon: '💍',
    img: 'https://picsum.photos/seed/cat-ring/600/800',
  },
  {
    name: 'Earrings',
    count: '52 items',
    icon: '✨',
    img: 'https://picsum.photos/seed/cat-earring/600/800',
  },
  {
    name: 'Bracelets',
    count: '36 items',
    icon: '⭕',
    img: 'https://picsum.photos/seed/cat-bracelet/600/800',
  },
];

function Categories() {
  return (
    <section className="categories-section">
      <h2 className="section-title">Shop by Category</h2>
      <div className="gold-divider"></div>
      <p className="section-subtitle">Explore our curated jewellery collections</p>

      <div className="categories-grid">
        {CATEGORIES.map((cat) => (
          <Link to="/shop" key={cat.name} className="category-card">
            <img
              src={cat.img}
              alt={cat.name}
              className="category-img"
              onError={e => { e.target.onerror = null; e.target.src = `https://placehold.co/600x800/f5f0e8/b8860b?text=${encodeURIComponent(cat.name)}`; }}
            />
            <div className="category-overlay">
              <span className="category-icon">{cat.icon}</span>
              <span className="category-name">{cat.name}</span>
              <span className="category-count">{cat.count}</span>
            </div>
          </Link>
        ))}
      </div>
    </section>
  );
}

export default Categories;
